namespace sv_c880c8d51a704efd954fa3625d901b6b.Client.Models;

public sealed class Shipment
{
    public required string TrackingNumber { get; init; }
    public required string Status { get; init; }
    public required string Location { get; init; }
    public DateTimeOffset? EstimatedDelivery { get; init; }
    public required IReadOnlyList<StatusUpdate> StatusUpdates { get; init; }
}

public sealed class StatusUpdate
{
    public required string Description { get; init; }
    public required DateTimeOffset Timestamp { get; init; }
    public string? Location { get; init; }
}

using sv_c880c8d51a704efd954fa3625d901b6b.Client.Models;

namespace sv_c880c8d51a704efd954fa3625d901b6b.Client.Services;

public interface IShipmentService
{
    Task<Shipment?> GetShipmentAsync(string trackingNumber, CancellationToken ct);
}

using sv_c880c8d51a704efd954fa3625d901b6b.Client.Models;
using sv_c880c8d51a704efd954fa3625d901b6b.Client.Services;

namespace sv_c880c8d51a704efd954fa3625d901b6b.Services;

public sealed class ShipmentService : IShipmentService
{
    private static readonly Dictionary<string, Shipment> SeedData = new(StringComparer.OrdinalIgnoreCase)
    {
        ["PKG-001"] = new Shipment
        {
            TrackingNumber = "PKG-001",
            Status = "In Transit",
            Location = "Memphis, TN",
            EstimatedDelivery = new DateTimeOffset(2026, 5, 26, 18, 0, 0, TimeSpan.Zero),
            StatusUpdates =
            [
                new StatusUpdate { Description = "Package picked up", Timestamp = new DateTimeOffset(2026, 5, 20, 9, 0, 0, TimeSpan.Zero), Location = "New York, NY" },
                new StatusUpdate { Description = "Arrived at sorting facility", Timestamp = new DateTimeOffset(2026, 5, 21, 3, 30, 0, TimeSpan.Zero), Location = "Newark, NJ" },
                new StatusUpdate { Description = "Departed facility", Timestamp = new DateTimeOffset(2026, 5, 22, 7, 15, 0, TimeSpan.Zero), Location = "Newark, NJ" },
                new StatusUpdate { Description = "In transit", Timestamp = new DateTimeOffset(2026, 5, 23, 2, 0, 0, TimeSpan.Zero), Location = "Memphis, TN" },
            ]
        },
        ["PKG-002"] = new Shipment
        {
            TrackingNumber = "PKG-002",
            Status = "Delivered",
            Location = "San Francisco, CA",
            EstimatedDelivery = new DateTimeOffset(2026, 5, 22, 17, 0, 0, TimeSpan.Zero),
            StatusUpdates =
            [
                new StatusUpdate { Description = "Package picked up", Timestamp = new DateTimeOffset(2026, 5, 18, 10, 0, 0, TimeSpan.Zero), Location = "Seattle, WA" },
                new StatusUpdate { Description = "In transit", Timestamp = new DateTimeOffset(2026, 5, 19, 14, 0, 0, TimeSpan.Zero), Location = "Portland, OR" },
                new StatusUpdate { Description = "Out for delivery", Timestamp = new DateTimeOffset(2026, 5, 22, 8, 30, 0, TimeSpan.Zero), Location = "San Francisco, CA" },
                new StatusUpdate { Description = "Delivered", Timestamp = new DateTimeOffset(2026, 5, 22, 14, 45, 0, TimeSpan.Zero), Location = "San Francisco, CA" },
            ]
        },
        ["PKG-003"] = new Shipment
        {
            TrackingNumber = "PKG-003",
            Status = "Processing",
            Location = "Chicago, IL",
            EstimatedDelivery = new DateTimeOffset(2026, 5, 28, 20, 0, 0, TimeSpan.Zero),
            StatusUpdates =
            [
                new StatusUpdate { Description = "Label created", Timestamp = new DateTimeOffset(2026, 5, 23, 6, 0, 0, TimeSpan.Zero), Location = "Chicago, IL" },
            ]
        },
    };

    public async Task<Shipment?> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        await Task.Delay(1500, ct);
        SeedData.TryGetValue(trackingNumber, out var shipment);
        return shipment;
    }
}

using System.Net.Http.Json;
using sv_c880c8d51a704efd954fa3625d901b6b.Client.Models;

namespace sv_c880c8d51a704efd954fa3625d901b6b.Client.Services;

/// <summary>
/// HTTP-based implementation used when running on WebAssembly.
/// Calls the server API to retrieve shipment data.
/// </summary>
public sealed class ShipmentServiceClient(HttpClient httpClient) : IShipmentService
{
    public async Task<Shipment?> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        var response = await httpClient.GetAsync($"api/shipments/{Uri.EscapeDataString(trackingNumber)}", ct);

        if (response.StatusCode == System.Net.HttpStatusCode.NotFound)
            return null;

        response.EnsureSuccessStatusCode();
        return await response.Content.ReadFromJsonAsync<Shipment>(ct);
    }
}

@page "/shipments/{TrackingNumber}"
@rendermode InteractiveAuto
@using sv_c880c8d51a704efd954fa3625d901b6b.Client.Models
@using sv_c880c8d51a704efd954fa3625d901b6b.Client.Services
@inject IShipmentService ShipmentService
@inject ILogger<ShipmentTracker> Logger
@implements IDisposable

@if (_loading)
{
    <div class="loading-placeholder">
        <p>Loading shipment details for <strong>@TrackingNumber</strong>...</p>
    </div>
}
else if (_errorMessage is not null)
{
    <div class="error-message">
        <p>@_errorMessage</p>
        <button @onclick="RetryLoad">Retry</button>
    </div>
}
else if (_shipment is null)
{
    <div class="not-found">
        <p>No shipment found for tracking number <strong>@TrackingNumber</strong>.</p>
    </div>
}
else
{
    <div class="shipment-details">
        <h2>Shipment @_shipment.TrackingNumber</h2>
        <dl>
            <dt>Status</dt>
            <dd>@_shipment.Status</dd>

            <dt>Location</dt>
            <dd>@_shipment.Location</dd>

            @if (_shipment.EstimatedDelivery.HasValue)
            {
                <dt>Estimated Delivery</dt>
                <dd>@_shipment.EstimatedDelivery.Value.ToString("f")</dd>
            }
        </dl>

        <h3>Tracking History</h3>
        <ul class="status-updates">
            @foreach (var update in _shipment.StatusUpdates)
            {
                <li>
                    <time datetime="@update.Timestamp.ToString("o")">@update.Timestamp.ToString("g")</time>
                    &mdash; @update.Description
                    @if (update.Location is not null)
                    {
                        <span class="update-location">(@update.Location)</span>
                    }
                </li>
            }
        </ul>
    </div>
}

@code {
    [Parameter]
    public string TrackingNumber { get; set; } = default!;

    private Shipment? _shipment;
    private bool _loading;
    private string? _errorMessage;
    private CancellationTokenSource? _cts;
    private string? _lastLoadedTrackingNumber;

    protected override async Task OnParametersSetAsync()
    {
        if (string.Equals(_lastLoadedTrackingNumber, TrackingNumber, StringComparison.OrdinalIgnoreCase))
            return;

        await LoadShipmentAsync();
    }

    private async Task LoadShipmentAsync()
    {
        // Cancel any in-flight request
        CancelPendingRequest();

        _lastLoadedTrackingNumber = TrackingNumber;
        _shipment = null;
        _errorMessage = null;
        _loading = true;
        StateHasChanged();

        var cts = new CancellationTokenSource();
        _cts = cts;

        try
        {
            _shipment = await ShipmentService.GetShipmentAsync(TrackingNumber, cts.Token);
        }
        catch (OperationCanceledException) when (cts.IsCancellationRequested)
        {
            // Request was intentionally cancelled (navigation or dispose); do nothing.
            return;
        }
        catch (TaskCanceledException ex) when (ex.InnerException is TimeoutException || ex.CancellationToken != cts.Token)
        {
            Logger.LogError(ex, "Timeout loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "Something went wrong while loading the shipment. Please try again.";
        }
        finally
        {
            _loading = false;
            StateHasChanged();
        }
    }

    private async Task RetryLoad()
    {
        _lastLoadedTrackingNumber = null;
        await LoadShipmentAsync();
    }

    private void CancelPendingRequest()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
    }

    public void Dispose()
    {
        CancelPendingRequest();
    }
}

